    /**
     * Rate limit QPS for matching hosts (0 = use global default)
     */
    rateLimitQPS?: number;
    /**
     * Rate limit burst for matching hosts (0 = use global default)
     */
    rateLimitBurst?: number;
    block?: {
        resourceTypes?: Array<'image' | 'media' | 'font' | 'stylesheet' | 'other'>;
        urlPatterns?: Array<string>;
    };
    wait?: {
        mode?: 'dom_ready' | 'network_idle' | 'stability' | 'selector';
        selector?: string;
        networkIdleQuietMs?: number;
        minTextLength?: number;
        stabilityPollMs?: number;
        stabilityIterations?: number;
        extraSleepMs?: number;
    };
    timeouts?: {
        maxRenderMs?: number;
        scriptEvalMs?: number;
        navigationMs?: number;
    };
    screenshot?: {
        enabled?: boolean;
        fullPage?: boolean;
        format?: 'png' | 'jpeg';
        quality?: number;
        width?: number;
        height?: number;
    };
    device?: {
        name?: string;
        viewportWidth?: number;
        viewportHeight?: number;
        deviceScaleFactor?: number;
        userAgent?: string;
        isMobile?: boolean;
        hasTouch?: boolean;
    };
